// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/// Build a string (usable as ispanstream) from a string_view of raw bytes
inline auto make_istream(std::string_view sv) {
    return std::ispanstream{sv};
}

/// Serialize msg and return the raw bytes as std::string
template<proto23::message Msg>
std::string to_bytes(const Msg& msg) {
    std::ostringstream oss;
    proto23::serialize(oss, msg);
    return oss.str();
}

/// Round-trip: serialize then deserialize; return the deserialized value
template<proto23::message Msg>
Msg round_trip(const Msg& original) {
    const auto data = to_bytes(original);
    auto in = std::ispanstream{data};
    Msg result{};
    std::ignore = proto23::deserialize(in, result);
    return result;
}

/// Equality helpers for types without operator==

inline bool eq_inner(const Inner& a, const Inner& b) {
    return a.status == b.status && a.v == b.v;
}
inline bool eq_outer(const Outer& a, const Outer& b) {
    return eq_inner(a.inner, b.inner) && a.v == b.v;
}

// Literal operators for proto wire types
[[maybe_unused]] constexpr auto operator""_i32(unsigned long long v) { return int32(v);    }
[[maybe_unused]] constexpr auto operator""_s32(unsigned long long v) { return sint32(v);   }
[[maybe_unused]] constexpr auto operator""_u32(unsigned long long v) { return uint32(v);   }
[[maybe_unused]] constexpr auto operator""_f32(unsigned long long v) { return fixed32(v);  }
[[maybe_unused]] constexpr auto operator""_sf32(unsigned long long v){ return sfixed32(v); }
[[maybe_unused]] constexpr auto operator""_i64(unsigned long long v) { return int64(v);    }
[[maybe_unused]] constexpr auto operator""_s64(unsigned long long v) { return sint64(v);   }
[[maybe_unused]] constexpr auto operator""_u64(unsigned long long v) { return uint64(v);   }
[[maybe_unused]] constexpr auto operator""_f64(unsigned long long v) { return fixed64(v);  }
[[maybe_unused]] constexpr auto operator""_sf64(unsigned long long v){ return sfixed64(v); }

// Negate proto enum types for test convenience
template<typename T>
    requires (proto23::detail::anyof<std::is_same, T,
        sint32, int32, sfixed32, sint64, int64, sfixed64>())
constexpr T operator-(T v) {
    return static_cast<T>(-static_cast<std::underlying_type_t<T>>(v));
}

inline std::string bytes(std::string_view sv) { return std::string{sv}; } //FIXME

// ---------------------------------------------------------------------------
// Deserialization test runner
// ---------------------------------------------------------------------------

/// Run a single deserialise test: feed wire bytes, compare with expected value
template<proto23::message Msg, typename EqFn>
void test_deser(const char* name,
                Msg expected,
                std::string_view wire,
                EqFn eq_fn)
{
    test(name) = [expected = std::move(expected), wire, eq_fn = std::move(eq_fn)] () mutable {
        auto in = make_istream(wire);
        Msg actual{};
        const auto result = proto23::deserialize(in, actual);
        if (wire.empty()) {
            expect(that % !any(result)) << "empty input should yield empty result";
        } else {
            expect(that % any(result)) << "should deserialize at least one field";
        }
        expect(that % eq_fn(actual, expected)) << "value mismatch";
    };
}

/// Simpler variant for types with operator==
template<proto23::message Msg>
void test_deser(const char* name, Msg expected, std::string_view wire) {
    test_deser(name, std::move(expected), wire, [](const Msg& a, const Msg& b) { return a == b; });
}

// ---------------------------------------------------------------------------
// Serialization + round-trip test runner
// ---------------------------------------------------------------------------

template<proto23::message Msg, typename EqFn>
void test_roundtrip(const char* name, const Msg& msg, EqFn&& eq_fn) {
    test(name) = [=] {
        const Msg rt = round_trip(msg);
        expect(that % eq_fn(rt, msg)) << "round-trip value mismatch";
    };
}

template<proto23::message Msg>
void test_roundtrip(const char* name, const Msg& msg) {
    test_roundtrip(name, msg, [](const Msg& a, const Msg& b) { return a == b; });
}

/// Exact binary match: serialize(msg) must equal wire
template<proto23::message Msg>
void test_exact(const char* name, Msg msg, std::string_view wire) {
    test(name) = [msg = std::move(msg), wire] {
        const auto data = to_bytes(msg);
        expect(eq(data.size(), wire.size())) << "wire length mismatch";
        if (data.size() == wire.size()) {
            expect(that % (std::memcmp(data.data(), wire.data(), wire.size()) == 0))
                << "wire bytes mismatch";
        }
    };
}

