// ===========================================================================
//  Oneof
// ===========================================================================
inline bool eq_union(const Union& a, const Union& b) {
    if (a.v != b.v) { return false; }
    if (a.v == 1)   { return std::abs(a.value - b.value) < 1e-6; }
    return a.count == b.count;
}

suite<"des/oneof"> oneof_deser = [] {
    // Variant (std::variant)
    test_deser("variant_double", Variant{1, {1.0}},
               "\x08\x02\x11\x00\x00\x00\x00\x00\x00\xF0\x3F"sv);
    test_deser("variant_int",    Variant{2, {2}},
               "\x08\x04\x18\x04"sv);

    // Union — needs custom equality
    test_deser("union_double", Union{1, {.value=1.0}},
               "\x08\x02\x11\x00\x00\x00\x00\x00\x00\xF0\x3F"sv, eq_union);
    test_deser("union_int",    Union{2, {.count=2}},
               "\x08\x04\x18\x04"sv, eq_union);
};

suite<"ser/oneof"> oneof_ser = [] {
    test_exact("variant_double", Variant{1, {1.0}},
               "\x08\x02\x11\x00\x00\x00\x00\x00\x00\xF0\x3F"sv);
    test_exact("variant_int",    Variant{2, {2}},
               "\x08\x04\x18\x04"sv);
    test_roundtrip("rt/variant_double", Variant{1, {1.0}});
    test_roundtrip("rt/variant_int",    Variant{3, {42}});
    test_roundtrip("rt/variant_string", Variant{0, {}});
};

// ===========================================================================
//  Optional
// ===========================================================================
auto eq_optional = [](const Optional& a, const Optional& b) {
    if (a.v != b.v) { return false; }
    if (a.inner.has_value() != b.inner.has_value()) { return false; }
    if (!a.inner.has_value()) { return true; }
    return eq_inner(*a.inner, *b.inner);
};

suite<"des/optional"> optional_deser = [] {
    test_deser("both",
               Optional{Inner{Status::OK, 2}, 1},
               "\x0A\x04\x08\x2A\x10\x04\x10\x02"sv, eq_optional);
    test_deser("none",
               Optional{{}, 1},
               "\x10\x02"sv, eq_optional);
};

suite<"ser/optional"> optional_ser = [] {
    test_exact("both",
               Optional{Inner{Status::OK, 2}, 1},
               "\x0A\x04\x08\x2A\x10\x04\x10\x02"sv);
    test_roundtrip("rt/both",  Optional{Inner{Status::OK, 42}, 7}, eq_optional);
    test_roundtrip("rt/none",  Optional{{}, 3},                    eq_optional);
};

// ===========================================================================
//  unique_ptr (Pointer)
// ===========================================================================
auto eq_pointer = [](const Pointer& a, const Pointer& b) {
    if (a.v != b.v) { return false; }
    if ((a.inner == nullptr) != (b.inner == nullptr)) { return false; }
    if (!a.inner) { return true; }
    return eq_inner(*a.inner, *b.inner);
};

suite<"des/pointer"> pointer_deser = [] {
    test_deser("with_inner",
               Pointer{std::make_unique<Inner>(Inner{Status::OK, 2}), 1},
               "\x0A\x04\x08\x2A\x10\x04\x10\x02"sv, eq_pointer);
    test_deser("no_inner",
               Pointer{{}, 1},
               "\x10\x02"sv, eq_pointer);
};

suite<"ser/pointer"> pointer_ser = [] {
    test_exact("with_inner",
               Pointer{std::make_unique<Inner>(Inner{Status::OK, 2}), 1},
               "\x0A\x04\x08\x2A\x10\x04\x10\x02"sv);
    // round-trip
    test("rt/pointer_with_inner") = [] {
        Pointer orig{std::make_unique<Inner>(Inner{Status::OK, 42}), 7};
        const auto rt = round_trip(orig);
        expect(that % eq_pointer(rt, orig));
    };
};

